def boundary_search(arr, target, find_first):
    low = 0
    high = len(arr) - 1
    ans = -1

    while low <= high:
        mid = (low + high) // 2

        if arr[mid] == target:
            ans = mid
            if find_first:
                high = mid - 1
            else:
                low = mid + 1
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1

    return ans


def first_last_occurrence(arr, target):
    first = boundary_search(arr, target, True)
    last = boundary_search(arr, target, False)
    return (first, last)

print(first_last_occurrence([1, 2, 2, 2, 3, 4], 2))
print(first_last_occurrence([1, 3, 5], 2))

def search_rotated(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) // 2

        if arr[mid] == target:
            return mid

        if arr[low] <= arr[mid]:
            if arr[low] <= target < arr[mid]:
                high = mid - 1
            else:
                low = mid + 1
        else:
            if arr[mid] < target <= arr[high]:
                low = mid + 1
            else:
                high = mid - 1

    return -1

print(search_rotated([4,5,6,7,0,1,2], 0))
print(search_rotated([4,5,6,7,0,1,2], 3))

def find_peak(arr):
    low = 0
    high = len(arr) - 1

    while low < high:
        mid = (low + high) // 2

        if arr[mid] < arr[mid + 1]:
            low = mid + 1
        else:
            high = mid

    return low

print(find_peak([1, 2, 3, 1]))
print(find_peak([1, 2, 1, 3, 5, 6, 4]))

import math

def can_finish(piles, h, speed):
    hours = 0
    for pile in piles:
        hours += math.ceil(pile / speed)
    return hours <= h


def min_eating_speed(piles, h):
    low = 1
    high = max(piles)
    ans = high

    while low <= high:
        mid = (low + high) // 2

        if can_finish(piles, h, mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1

    return ans

print(min_eating_speed([3, 6, 7, 11], 8))
print(min_eating_speed([30, 11, 23, 4, 20], 5))
